interface AnimatedCounterProps {
  value: number;
  duration?: number;
  isCurrency?: boolean;
}

function AnimatedCounter({ value, duration = 1000, isCurrency = false }: AnimatedCounterProps) {
  const [count, setCount] = React.useState(0);

  React.useEffect(() => {
    let startTimestamp: number | null = null;
    const startValue = count;
    const endValue = value;
    
    if (startValue === endValue) return;

    let animFrame: number;
    const step = (timestamp: number) => {
      if (!startTimestamp) startTimestamp = timestamp;
      const progress = Math.min((timestamp - startTimestamp) / duration, 1);
      // Easing out quad
      const easedProgress = progress * (2 - progress);
      const currentCount = startValue + (endValue - startValue) * easedProgress;
      setCount(currentCount);

      if (progress < 1) {
        animFrame = window.requestAnimationFrame(step);
      } else {
        setCount(endValue);
      }
    };

    animFrame = window.requestAnimationFrame(step);
    return () => window.cancelAnimationFrame(animFrame);
  }, [value, duration]);

  if (isCurrency) {
    return (
      <>
        R$ {count.toLocaleString("pt-BR", {
          minimumFractionDigits: 2,
          maximumFractionDigits: 2,
        })}
      </>
    );
  }

  return <>{Math.round(count).toLocaleString("pt-BR")}</>;
}

