  const [isSavingBillingConfig, setIsSavingBillingConfig] = useState(false);
  const handleSaveBillingConfig = async (newConfig: typeof billingConfig) => {
    setIsSavingBillingConfig(true);
    try {
      const diffs: string[] = [];
      const oldVal = dbBillingConfig || {};

      if (oldVal.defaultDaysToDue !== newConfig.defaultDaysToDue) {
        diffs.push(
          `Prazo padrão de vencimento: alterado de ${oldVal.defaultDaysToDue || 5} para ${newConfig.defaultDaysToDue} dias`,
        );
      }
      if (oldVal.acceptWeekendPayment !== newConfig.acceptWeekendPayment) {
        diffs.push(
          `Aceitar pagamentos no final de semana: alterado de ${oldVal.acceptWeekendPayment ? "Ativo" : "Inativo"} para ${newConfig.acceptWeekendPayment ? "Ativo" : "Inativo"}`,
        );
      }
      if (oldVal.calculationMethod !== newConfig.calculationMethod) {
        diffs.push(
          `Método de cálculo: alterado de ${oldVal.calculationMethod === "workdays" ? "Dias Úteis" : "Dias Corridos"} para ${newConfig.calculationMethod === "workdays" ? "Dias Úteis" : "Dias Corridos"}`,
        );
      }

      const daysTranslation: Record<string, string> = {
        monday: "Segunda-feira",
        tuesday: "Terça-feira",
        wednesday: "Quarta-feira",
        thursday: "Quinta-feira",
        friday: "Sexta-feira",
        saturday: "Sábado",
        sunday: "Domingo",
      };

      const oldWorkdays = oldVal.workdays || {};
      const newWorkdays = newConfig.workdays || {};
      Object.keys(daysTranslation).forEach((day) => {
        const oldDayVal =
          oldWorkdays[day] !== undefined
            ? oldWorkdays[day]
            : day !== "saturday" && day !== "sunday";
        const newDayVal = newWorkdays[day];
        if (oldDayVal !== newDayVal) {
          diffs.push(
            `Dia útil (${daysTranslation[day]}): alterado para ${newDayVal ? "Ativo" : "Inativo"}`,
          );
        }
      });

      await setDoc(doc(db, "settings", "billing_config"), {
        defaultDaysToDue: newConfig.defaultDaysToDue,
        acceptWeekendPayment: newConfig.acceptWeekendPayment,
        calculationMethod: newConfig.calculationMethod,
        workdays: newConfig.workdays,
        holidays: newConfig.holidays,
        updatedAt: new Date().toISOString(),
        updatedBy: currentUser?.email || "Contador Parceiro",
      });

      if (diffs.length > 0) {
        const logId = `log_${Date.now()}`;
        await setDoc(doc(db, "audit_logs", logId), {
          adminEmail: currentUser?.email || "Contador Parceiro",
          timestamp: new Date().toISOString(),
          changes: diffs,
          createdAt: serverTimestamp(),
        });
        refetchAuditLogs();
      }

      showNotification(
        "success",
        "Configurações de dias úteis salvas com sucesso!",
      );
      refetchBillingConfig();
    } catch (err) {
      console.error("Erro ao salvar configurações de cobrança:", err);
      showNotification("error", "Erro ao salvar as configurações.");
    } finally {
      setIsSavingBillingConfig(false);
    }
  };

  const calculateDueDateTrace = (
    issueDateStr: string,
    days: number,
    method: "workdays" | "calendar",
    acceptWeekend: boolean,
    workdays: Record<string, boolean>,
    holidays: string[],
  ) => {
    if (!issueDateStr) return { date: null, trace: [] as string[] };
    const trace: string[] = [];
    const parts = issueDateStr.split("-");
    let currentDate = new Date(
      parseInt(parts[0]),
      parseInt(parts[1]) - 1,
      parseInt(parts[2]),
      12,
      0,
      0,
    );
    const dayNames = [
      "sunday",
      "monday",
      "tuesday",
      "wednesday",
      "thursday",
      "friday",
      "saturday",
    ];
    const dayNamesPt = [
      "Domingo",
      "Segunda-feira",
      "Terça-feira",
      "Quarta-feira",
      "Quinta-feira",
      "Sexta-feira",
      "Sábado",
    ];

    trace.push(
      `Data de Emissão selecionada: ${currentDate.toLocaleDateString("pt-BR")} (${dayNamesPt[currentDate.getDay()]})`,
    );

    const isHoliday = (date: Date) => {
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, "0");
      const day = String(date.getDate()).padStart(2, "0");
      const formatted = `${year}-${month}-${day}`;
      return holidays.includes(formatted);
    };

    const isWorkday = (date: Date) => {
      const dayName = dayNames[date.getDay()];
      const isWeekWorkday = workdays[dayName] === true;
      return isWeekWorkday && !isHoliday(date);
    };

    if (method === "workdays") {
      trace.push(`Modo selecionado: Contar apenas DIAS ÚTEIS (${days} dias)`);
      let daysCounted = 0;
      let iterations = 0;
      while (daysCounted < days && iterations < 100) {
        iterations++;
        currentDate.setDate(currentDate.getDate() + 1);
        const dayNamePt = dayNamesPt[currentDate.getDay()];
        const formattedDate = currentDate.toLocaleDateString("pt-BR");

        if (isHoliday(currentDate)) {
          trace.push(`⏩ ${formattedDate} (${dayNamePt}) é Feriado. Ignorado.`);
        } else if (!workdays[dayNames[currentDate.getDay()]]) {
          trace.push(
            `⏩ ${formattedDate} (${dayNamePt}) não é dia útil de trabalho. Ignorado.`,
          );
        } else {
          daysCounted++;
          trace.push(
            `✅ Dia Útil ${daysCounted}: ${formattedDate} (${dayNamePt})`,
          );
        }
      }
    } else {
      trace.push(`Modo selecionado: Contar DIAS CORRIDOS (${days} dias)`);
      currentDate.setDate(currentDate.getDate() + days);
      trace.push(
        `📅 Data calculada corrida: ${currentDate.toLocaleDateString("pt-BR")} (${dayNamesPt[currentDate.getDay()]})`,
      );
    }

    if (!acceptWeekend) {
      let rollCount = 0;
      while (!isWorkday(currentDate) && rollCount < 30) {
        rollCount++;
        const dayNamePt = dayNamesPt[currentDate.getDay()];
        const formattedDate = currentDate.toLocaleDateString("pt-BR");
        if (isHoliday(currentDate)) {
          trace.push(
            `⚠️ ${formattedDate} (${dayNamePt}) é Feriado e vencimentos no final de semana/feriado estão desativados.`,
          );
        } else {
          trace.push(
            `⚠️ ${formattedDate} (${dayNamePt}) não é dia útil e vencimentos no final de semana estão desativados.`,
          );
        }
        currentDate.setDate(currentDate.getDate() + 1);
        trace.push(
          `↪️ Prorrogando para o próximo dia útil: ${currentDate.toLocaleDateString("pt-BR")} (${dayNamesPt[currentDate.getDay()]})`,
        );
      }
    } else {
      trace.push(
        `ℹ️ Vencimentos no final de semana estão permitidos, mantendo data calculada.`,
      );
    }

    return {
      date: currentDate,
      trace,
    };
  };

