  const handleLinkCnpj = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;
    if (!cnpjToLink.trim()) {
      setLinkingMessage({ type: "error", text: "Por favor, informe o CNPJ." });
      return;
    }

    setIsLinkingCnpj(true);
    setLinkingMessage(null);

    try {
      const cleanCnpj = cnpjToLink.replace(/\D/g, "");
      const q = query(
        collection(db, "members"),
        where("cnpj", "==", cnpjToLink.trim()),
      );
      const snapshot = await getDocs(q);

      if (snapshot.empty) {
        const qClean = query(
          collection(db, "members"),
          where("cnpj", "==", cleanCnpj),
        );
        const snapClean = await getDocs(qClean);

        if (snapClean.empty) {
          setLinkingMessage({
            type: "error",
            text: "Empresa com este CNPJ não localizada no cadastro de associados. Entre em contato com a administração.",
          });
          setIsLinkingCnpj(false);
          return;
        }

        const docId = snapClean.docs[0].id;
        await updateDoc(doc(db, "members", docId), {
          userId: currentUser.uid,
        });
        setLinkingMessage({
          type: "success",
          text: "Parabéns! Empresa vinculada com sucesso ao seu perfil de associado.",
        });
        refetchMemberProfile();
        setIsLinkingCnpj(false);
        return;
      }

      const docId = snapshot.docs[0].id;
      await updateDoc(doc(db, "members", docId), {
        userId: currentUser.uid,
      });
      setLinkingMessage({
        type: "success",
        text: "Parabéns! Empresa vinculada com sucesso ao seu perfil de associado.",
      });
      refetchMemberProfile();
    } catch (err: any) {
      console.error("Erro ao vincular CNPJ:", err);
      setLinkingMessage({
        type: "error",
        text: "Ocorreu um erro ao vincular a empresa. " + (err.message || ""),
      });
    } finally {
      setIsLinkingCnpj(false);
    }
  };

  const handleApproveRequest = async (request: any) => {
    try {
      setGlobalMessage({
        type: "info",
        text: `Aprovando solicitação de ${request.companyName}...`,
      });

      // 1. Criar o Associado (Membro)
      const memberRef = await addDoc(collection(db, "members"), {
        name: request.companyName,
        cnpj: request.cnpj,
        email: request.email,
        phone: request.phone,
        representative: request.representative,
        level: "Bronze",
        status: "active", // 'active' conforme regras
        createdAt: serverTimestamp(),
        requestId: request.id,
      });

      // 2. Gerar 12 mensalidades (Boletos) na sub-coleção
      const monthlyValue = 150.0;
      const today = new Date();

      for (let i = 0; i < 12; i++) {
        const dueDate = new Date(
          today.getFullYear(),
          today.getMonth() + i + 1,
          15,
        );
        await addDoc(collection(db, "members", memberRef.id, "boletos"), {
          memberId: memberRef.id,
          memberName: request.companyName, // Adicionado para facilitar listagem
          title: `Mensalidade ${dueDate.getMonth() + 1}/${dueDate.getFullYear()}`,
          amount: monthlyValue,
          dueDate: Timestamp.fromDate(dueDate),
          status: "pending",
          createdAt: serverTimestamp(),
        });
      }

      // 3. Atualizar status da solicitação
      await updateDoc(doc(db, "membership_requests", request.id), {
        status: "approved",
        approvedAt: serverTimestamp(),
      });

      showNotification(
        "success",
        `Associado ${request.companyName} aprovado e 12 mensalidades geradas!`,
      );
      fetchMembershipRequests();
    } catch (error: any) {
      console.error("Error approving request:", error);
      showNotification("error", "Falha ao aprovar: " + error.message);
    }
  };

