  const submitSuggestion = async (e: React.FormEvent) => {
    e.preventDefault();
    setSuggestionStatus(null);

    // Validation
    if (!suggestionForm.name.trim()) {
      setSuggestionStatus({
        type: "error",
        message: "Por favor, informe seu nome completo.",
      });
      return;
    }

    if (!suggestionForm.email.trim()) {
      setSuggestionStatus({
        type: "error",
        message: "O e-mail é obrigatório.",
      });
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(suggestionForm.email)) {
      setSuggestionStatus({
        type: "error",
        message: "Por favor, insira um e-mail válido.",
      });
      return;
    }

    if (!suggestionForm.message.trim()) {
      setSuggestionStatus({
        type: "error",
        message: "A mensagem da sugestão não pode estar vazia.",
      });
      return;
    }

    if (suggestionForm.message.length < 10) {
      setSuggestionStatus({
        type: "error",
        message:
          "Por favor, descreva sua sugestão com pelo menos 10 caracteres.",
      });
      return;
    }

    setIsSendingSuggestion(true);
    try {
      await addDoc(collection(db, "suggestions"), {
        userId: currentUser?.uid || null,
        name: suggestionForm.name,
        email: suggestionForm.email,
        message: suggestionForm.message,
        createdAt: Timestamp.now(),
      });
      setSuggestionForm({ name: "", email: "", message: "" });
      showNotification(
        "success",
        "Sugestão enviada com sucesso! Agradecemos sua contribuição.",
      );
    } catch (error) {
      console.error("Erro ao enviar sugestão:", error);
      showNotification(
        "error",
        "Não foi possível enviar sua sugestão: " +
          getFriendlyErrorMessage(error),
      );
      handleFirestoreError(error, OperationType.WRITE, "suggestions");
    } finally {
      setIsSendingSuggestion(false);
    }
  };

